2082 
2083   for (Instruction *Negatible : Candidates) {
2084     const APFloat *C;
2085     if (match(Negatible->getOperand(0), m_APFloat(C))) {
2086       assert(!match(Negatible->getOperand(1), m_Constant()) &&
2087              "Expecting only 1 constant operand");
